    <script>
        function formatXml(xml) {
            const PADDING = '  '; // Define indentation
            const reg = /(>)(<)(\/*)/g;
            let formatted = '';
            let pad = 0;

            // Add new lines and indentation
            xml = xml.replace(reg, '$1\r\n$2$3');
            xml.split('\r\n').forEach((node) => {
                let indent = 0;
                if (node.match(/.+<\/\w[^>]*>$/)) {
                    indent = 0;
                } else if (node.match(/^<\/\w/)) {
                    if (pad !== 0) {
                        pad -= 1;
                    }
                } else if (node.match(/^<\w[^>]*[^\/]>.*$/)) {
                    indent = 1;
                } else {
                    indent = 0;
                }

                formatted += PADDING.repeat(pad) + node + '\r\n';
                pad += indent;
            });

            return formatted.trim();
        }
        function styleXml(xml) {
            // Regular expressions for tags, attributes, and content
            const tagRegex = /(&lt;\/?[^&gt;]+&gt;)/g;
            const attrRegex = /(\w+)=("[^"]*")/g;

            // Replace < and > with HTML-safe characters
            xml = xml.replace(/</g, '&lt;').replace(/>/g, '&gt;');

            // Add span classes for XML tags and attributes
            xml = xml.replace(tagRegex, function(match) {
                let styledTag = match.replace(attrRegex, '<span class="xml-attribute">$1=$2</span>');
                return `<span class="xml-tag">${styledTag}</span>`;
            });

            // Return the styled XML
            return xml;
        }
        function sendSpriJob(gf_meldung_id) {
            const xhr = new XMLHttpRequest();
            let interneAuftragsId;
            if(parseInt(gf_meldung_id) > 9) {
                gf_meldung_id=parseInt(gf_meldung_id)-10;
                interneAuftragsId = document.getElementById("auftragegepv").value;
            } else {
                interneAuftragsId = document.getElementById("auftragege").value;
            }

            let gfm_id = 10*(parseInt(interneAuftragsId)-1)+parseInt(gf_meldung_id);
            console.log(gfm_id);
            xhr.open("POST", "http://localhost/oass/v4/sendeGfMeldung/"+gfm_id, true);
            xhr.setRequestHeader("Content-Type", "text/xml");
            xhr.setRequestHeader("SOAPAction", "http://spri.telekom.de/oss/v4/spri/annehmenMeldung");

            xhr.onreadystatechange = function () {
                if (xhr.readyState === 4) {
                    console.dir(xhr.status);
                    if (xhr.status === 200) {
                        console.dir(xhr.getResponseHeader("Content-Type"));
                        if(xhr.responseText.includes("annehmenMeldungResponse")) {
                            const arr = JSON.parse(xhr.responseText);
                            console.dir(arr[0]);
                            console.dir(arr[1]);
                            document.getElementById("request").innerText = formatXml(arr[0]);
                            document.getElementById("response").innerText = formatXml(arr[1]);
                        } else {
                            console.dir(xhr);

                            if(xhr.getResponseHeader("Content-Type").indexOf("text/html") >= 0)
                            {
                                const parser = new DOMParser();
                                const response = parser.parseFromString(xhr.responseText, "text/html");
                                document.getElementById("error-row").classList.replace("invisible", "visible");
                                document.getElementById("error-body").appendChild(response.getElementById("wrapper"));
                            }
                            else if(xhr.getResponseHeader("Content-Type").indexOf("text/xml") >= 0)
                            {
                                document.getElementById("error-row").classList.replace("invisible", "visible");
                                document.getElementById("error-body").innerText = formatXml(xhr.responseText);
                            }

                        }
                    } else {
                        console.dir(xhr.responseText);
                        let content_type = xhr.getResponseHeader("Content-Type");
                        console.dir(content_type);

                        if(content_type.indexOf("text/html") >= 0)
                        {
                            const parser = new DOMParser();
                            const response = parser.parseFromString(xhr.responseText, "text/html");
                            document.getElementById("error-row").classList.replace("invisible", "visible");
                            document.getElementById("error-body").appendChild(response.getElementById("wrapper"));
                        }
                        else if(content_type.indexOf("text/xml") >= 0)
                        {
                            document.getElementById("error-row").classList.replace("invisible", "visible");
                            document.getElementById("error-body").innerText = formatXml(xhr.responseText);
                        }

                    }
                }
            };

            xhr.send();

        }


        function sendSpriMessage(type, code, sender) {

